import{c as a,Q as t,j as s,m as o}from"./chunks/framework.BPKcPtvA.js";const h=JSON.parse('{"title":"Passkey accounts","description":"How your passkey-bound smart account works and what it protects.","frontmatter":{"title":"Passkey accounts","description":"How your passkey-bound smart account works and what it protects."},"headers":[],"relativePath":"get-started/passkey-accounts.md","filePath":"get-started/passkey-accounts.md","lastUpdated":1778983454000}'),n={name:"get-started/passkey-accounts.md"};function r(i,e,d,l,p,c){return t(),s("div",null,[...e[0]||(e[0]=[o(`<h1 id="passkey-accounts" tabindex="-1">Passkey accounts <a class="header-anchor" href="#passkey-accounts" aria-label="Permalink to &quot;Passkey accounts&quot;">​</a></h1><p>MuHaven uses <strong>WebAuthn passkeys</strong> as the root of trust for every account. There is no seed phrase, no browser-extension wallet, and no private key on your device. Your <strong>biometric or hardware key</strong> is the only signer.</p><h2 id="what-s-actually-behind-your-account" tabindex="-1">What&#39;s actually behind your account <a class="header-anchor" href="#what-s-actually-behind-your-account" aria-label="Permalink to &quot;What&#39;s actually behind your account&quot;">​</a></h2><p>Three layers work together:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>   You ────►  Passkey (WebAuthn credential on device / iCloud / Google PM / hardware key)</span></span>
<span class="line"><span>                    │</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>                 MuHaven wallet  (EIP-4337 smart account, ZeroDev-powered)</span></span>
<span class="line"><span>                    │   ├── First sign-in: passkey dialog → wallet deploy</span></span>
<span class="line"><span>                    │   ├── Subsequent writes: signed locally by a scoped session key</span></span>
<span class="line"><span>                    │   └── Session key TTL: default 1 hour (configurable)</span></span>
<span class="line"><span>                    ▼</span></span>
<span class="line"><span>              MuHaven contracts (Arbitrum) — encrypted RWA balances</span></span></code></pre></div><p><strong>Plain-English summary:</strong> your passkey signs an authorization that installs a short-lived &quot;session key&quot; with a <em>narrow scope</em> (only MuHaven functions, only your wallet, only for 1 hour). Day-to-day actions are signed by the session key — fast, no biometric prompt every click — until the hour runs out and you re-authorize.</p><h2 id="why-a-passkey-instead-of-a-wallet-extension" tabindex="-1">Why a passkey instead of a wallet extension <a class="header-anchor" href="#why-a-passkey-instead-of-a-wallet-extension" aria-label="Permalink to &quot;Why a passkey instead of a wallet extension&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Concern</th><th>Browser extension wallet</th><th>MuHaven wallet (passkey)</th></tr></thead><tbody><tr><td>Seed phrase to lose</td><td>Yes</td><td>No</td></tr><tr><td>Browser-extension supply-chain risk</td><td>High (qix incident, 2.6B weekly downloads)</td><td>None — no extension</td></tr><tr><td>Phishing-resistance</td><td>Site-name spoofable</td><td>WebAuthn RP-ID hard-pinned to <code>muhaven.app</code></td></tr><tr><td>Cross-device</td><td>Manual seed export</td><td>Passkey syncs via iCloud / Google PM / 1Password</td></tr><tr><td>Hardware key support</td><td>Some</td><td>Yes (any FIDO2 authenticator)</td></tr><tr><td>Gas paid in ETH</td><td>Yes</td><td>No — paymaster sponsors gas on Arb Sepolia</td></tr><tr><td>Recoverability</td><td>Seed phrase only</td><td>Multiple passkeys per wallet</td></tr></tbody></table><h2 id="where-your-passkey-works" tabindex="-1">Where your passkey works <a class="header-anchor" href="#where-your-passkey-works" aria-label="Permalink to &quot;Where your passkey works&quot;">​</a></h2><p>Your one MuHaven passkey signs across:</p><ul><li><strong>HavenBot</strong> in the dashboard (<code>muhaven.app/agent</code>).</li><li><strong><code>@muhaven/mcp</code></strong> when you complete the device-code authorization (a one-time passkey prompt at <code>muhaven.app/link?code=...</code>).</li><li><strong>OpenClaw / Telegram</strong> for the <strong>mid-tier (Mini-App OTP)</strong> and <strong>high-tier (deep-link passkey)</strong> confirmations.</li><li><strong>Hosted Checkout</strong> at <code>muhaven.app/pay/...</code> — first-time buyers create a passkey at checkout time; returning buyers reuse it.</li></ul><div class="warning custom-block"><p class="custom-block-title">RP-ID pinning</p><p>Passkeys are <em>bound to a domain</em> at the moment they&#39;re created. A passkey created on <code>muhaven.app</code> cannot be used at <code>muhaven-link.com</code> or any other domain — that&#39;s the load-bearing phishing-resistance control.</p><p>If MuHaven ever migrates domains (we did once: <code>*.hasto.dev → muhaven.app</code>, 2026-05-11), existing passkeys do NOT migrate. You&#39;ll need to register a new one. Your MuHaven wallet can hold multiple passkeys.</p></div><h2 id="sign-in-flow" tabindex="-1">Sign-in flow <a class="header-anchor" href="#sign-in-flow" aria-label="Permalink to &quot;Sign-in flow&quot;">​</a></h2><p>First time:</p><ol><li>Click <strong>Sign in</strong> on <code>muhaven.app</code>.</li><li>Pick <strong>Create a new passkey</strong>.</li><li>Approve with Touch ID / Windows Hello / hardware key.</li><li>Your MuHaven wallet deploys in the background, paymaster-sponsored.</li></ol><p>Every time after:</p><ol><li>Click <strong>Sign in</strong>.</li><li>Pick your passkey from the OS dialog.</li><li>You&#39;re in — no wallet redeploy.</li></ol><h2 id="choosing-a-passkey-provider" tabindex="-1">Choosing a passkey provider <a class="header-anchor" href="#choosing-a-passkey-provider" aria-label="Permalink to &quot;Choosing a passkey provider&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Provider</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>iCloud Keychain</strong> (Apple)</td><td>Syncs across all your Apple devices</td><td>Apple-only</td></tr><tr><td><strong>Google Password Manager</strong></td><td>Syncs across all your Google sign-in devices</td><td>Chrome / Android only</td></tr><tr><td><strong>1Password / Bitwarden</strong></td><td>Cross-platform, share with team</td><td>Requires the app installed</td></tr><tr><td><strong>Hardware key (YubiKey, Solo, Titan)</strong></td><td>Highest assurance; works offline</td><td>Single device unless you buy a backup</td></tr><tr><td><strong>Platform-only (no sync)</strong></td><td>Fastest setup</td><td>Lose the device → lose the key</td></tr></tbody></table><blockquote><p><strong>Recommendation:</strong> for personal use, iCloud Keychain or Google Password Manager are easiest. For higher assurance, a hardware key with a registered backup.</p></blockquote><h2 id="what-happens-if-you-lose-a-passkey" tabindex="-1">What happens if you lose a passkey <a class="header-anchor" href="#what-happens-if-you-lose-a-passkey" aria-label="Permalink to &quot;What happens if you lose a passkey&quot;">​</a></h2><ul><li>If your passkey is synced (iCloud / Google PM / 1Password), it survives the lost device — just sign in on a new device.</li><li>If it&#39;s not synced (platform-only or hardware key with no backup), the recovery path depends on whether you registered a backup passkey. Always register at least one backup credential.</li></ul><div class="tip custom-block"><p class="custom-block-title">Always register a backup</p><p>Register <strong>at least two</strong> passkeys per MuHaven wallet where supported. A second device, a second 1Password vault, a YubiKey kept at home — any of these are good. Your MuHaven wallet supports multiple credentials.</p></div><h2 id="what-muhaven-does-not-know-about-you" tabindex="-1">What MuHaven does NOT know about you <a class="header-anchor" href="#what-muhaven-does-not-know-about-you" aria-label="Permalink to &quot;What MuHaven does NOT know about you&quot;">​</a></h2><p>The dashboard backend sees:</p><ul><li>Your wallet address.</li><li>Your role (investor or issuer).</li><li>The aggregate event counts that drive the public metrics page.</li><li>Audit log entries that <strong>you</strong> wrote by taking actions.</li></ul><p>It does <strong>not</strong> see:</p><ul><li>Your passkey&#39;s private key (it&#39;s on your device or in your password manager).</li><li>Your encrypted balances in cleartext (FHE doesn&#39;t decrypt server-side).</li><li>Your strategy (the LLM-side context lives in your host, not on our servers — except for HavenBot, where the chat history is server-managed and you can clear it).</li></ul><p>See <a href="/get-started/privacy-boundary">Privacy boundary</a> for the full picture.</p>`,29)])])}const y=a(n,[["render",r]]);export{h as __pageData,y as default};
